import{c as l,Q as i,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/64-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/64-出使德意志皇帝.md"}'),c={name:"research/machiavelli/machiavelli/diplomatic/lower/64-出使德意志皇帝.md"};function o(n,a,s,m,d,p){return i(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝 整。诸位大人必须继续行使对我们所有城市、城堡、村庄和其他地方的司 法权和所有权，就像现在诸位大人实行和拥有的一样。此外，诸位大人的 尊严、权威和显赫，不能受到皇帝或他的任何下属的减损。马基雅维利对 这一点还进行了许多说明，不过都是同样的意思。我立刻请求觐见皇帝， 并且在马基雅维利到达之后的那个夜里受到皇帝接见。我尽量简洁地向皇 帝说明了诸位大人的观点和意图。 一开始，我按照马基雅维利告诉我的说 法，提出分三次付清30000达克特，并要求皇帝作为回报要承诺归还和保 护我们的领土。然后，克劳恩当着皇帝的面回答说，这次诸位大人给的钱 比1502年时给的更少，但我们要求的却更多。至于归还领土，就更不用说 了。看到如果我不放弃归还领土的问题，谈判很可能要破裂。而且如果不 提高价钱的话，对话可能也无法继续。我想不如把价钱提高到40000达克 特，并且让第一次付款的数目更加可观。这样，皇帝考虑到马上就可以收 到更多现钱(他觉得这相当重要),可能就会答应我们的要求。同时，这 样还可以给诸位大人省下10000达克特。所以我说道：因为知道诸位大人 对皇帝陛下极有诚意，所以我愿意冒险以诸位大人的名义承诺给出40000 达克特。其中16000达克特会在他进入完全属于意大利的第一个城镇时交 付，剩下的分两次付清，具体付款方式可以在这次协商中决定。我还说， 虽然诸位大人对比萨的事情极度重视，而且诸位大人在比萨的权力也比较 稳固，但是诸位大人仍会竭尽所能，以示对皇帝陛下的忠诚。诸位大人对 比萨的事情不会多说什么,只要求皇帝陛下保护诸位大人现有领土的安全 和完整。皇帝陛下对我所说的话，表示了明显的喜悦。在我看来，根据我 所能观察到的迹象，皇帝很可能会接受这个提议。不过，他同时让克劳恩 告诉我说，他愿意考虑这个提议，并且会在接下来的一天给我答复。 在我离开之前，皇帝把皮杰洛①叫到一边，询问他刚来的秘书是谁， 是从什么路线来的，并且说看来佛罗伦萨人似乎正在创造一个良好的开",-1),e("p",null,"①皮杰洛 · 波尔蒂纳里( Pigello Portinari), 一个佛罗伦萨人。——英译本注",-1),e("p",null,"Opere complete di Niccolo Machiavelli",-1)])])}const f=l(c,[["render",o]]);export{h as __pageData,f as default};
